        chapters: {
          "Mole Concept & Stoichiometry": {"formulas": [{"id": "mol1", "name": "Mole and Avogadro's Number", "equation": "1 mol = 6.022Г—10ВІВі particles;  n = m/M", "explanation": "n = moles, m = mass (g), M = molar mass (g/mol). Number of particles N = n Г— NвӮҗ. Molar volume of ideal gas at STP = 22.4 L.", "derived": "Avogadro's number defined so that 12g of В№ВІC contains exactly 6.022Г—10ВІВі atoms.", "related": ["Molarity", "Molality", "Equivalent Concept", "Avogadro's Number", "Molar Volume", "STP Conditions"], "jee": ["Converting mass to moles", "Number of atoms/molecules", "Molar volume at STP", "Gram-atom vs gram-molecule"]}, {"id": "mol2", "name": "Molarity and Molality", "equation": "M = n/V(L);  m = n/w(kg solvent)", "explanation": "Molarity M: moles of solute per litre of solution (temperature dependent). Molality m: moles per kg of solvent (temperature independent). Normality N = n_eq/V.", "derived": "Definitions of concentration. Molality preferred for colligative properties as it is T-independent.", "related": ["Mole Concept", "Normality", "Dilution Formula", "Mole Fraction", "Parts per Million"], "jee": ["Preparing solutions of given molarity", "MвӮҒVвӮҒ=MвӮӮVвӮӮ dilution", "Converting molarity to molality", "Normality for acid-base"]}, {"id": "mol3", "name": "Limiting Reagent and % Yield", "equation": "% yield = (actual yield/theoretical yield) Г— 100", "explanation": "Limiting reagent: consumed first, determines product amount. Theoretical yield from stoichiometry of limiting reagent. Excess reagent amount = initial вҲ’ consumed.", "derived": "From stoichiometric mole ratios in balanced equation.", "related": ["Mole Concept", "Stoichiometry", "Empirical Formula", "Yield Calculation", "Excess Reagent"], "jee": ["Identifying limiting reagent", "Calculating theoretical yield", "% yield problems", "Excess reagent remaining"]}, {"id": "mol4", "name": "Empirical and Molecular Formula", "equation": "Molecular formula = n Г— Empirical formula;  n = M/MвӮ‘", "explanation": "Empirical formula: simplest whole-number ratio of atoms. Molecular formula: actual number. n = molecular mass / empirical formula mass. Found from % composition.", "derived": "From elemental analysis: divide % by atomic mass, divide by smallest to get ratio.", "related": ["Mole Concept", "% Composition", "Limiting Reagent", "Degree of Unsaturation", "Combustion Analysis"], "jee": ["Finding EF from % composition", "Molecular formula from EF and M", "Combustion analysis", "Degree of unsaturation"]}, {"id": "mol5", "name": "Equivalent Concept and Normality", "equation": "N = n Г— n-factor;  NвӮҒVвӮҒ = NвӮӮVвӮӮ", "explanation": "Equivalent weight = M/n-factor. n-factor: acid (HвҒә per molecule), base (OHвҒ»), redox (electron transfer). Meq = N Г— V(mL). Equivalent of all species equal at equivalence point.", "derived": "Based on reacting equivalents being equal at equivalence point.", "related": ["Normality", "Redox Reactions", "Acid-Base Titration", "n-factor", "Equivalent Weight"], "jee": ["Back titration", "Redox equivalents", "Titration calculations", "n-factor determination"]}, {"id": "mol6", "name": "Redox Reactions вҖ” Oxidation Number", "equation": "Oxidation: ON increases (loses eвҒ»);  Reduction: ON decreases (gains eвҒ»)", "explanation": "Rules: O = вҲ’2 (usually); H = +1 (usually); F = вҲ’1 always; sum = charge. Disproportionation: same element oxidized and reduced. OIL RIG mnemonic.", "derived": "Formal assignment of electrons. Balancing redox by half-reaction or oxidation-number method.", "related": ["Equivalent Concept", "Electrochemistry", "Balancing Equations", "Oxidation Number", "Half Reaction"], "jee": ["Assigning oxidation numbers", "Balancing redox by ion-electron method", "Disproportionation reactions", "n-factor from redox"]}, {"id": "mol7", "name": "Concentration Interconversion", "equation": "M = (10 Г— d Г— %w/w)/M_r;  ПҮ = n/(n+N)", "explanation": "d = density (g/mL), %w/w = weight percent, M_r = molar mass. Mole fraction ПҮ: n = moles solute, N = moles solvent. Parts per million: ppm = (mass solute/mass solution) Г— 10вҒ¶.", "derived": "From definitions of concentration units. Interconversion requires density and molar mass.", "related": ["Molarity", "Mole Fraction", "Colligative Properties", "Density of Solution", "ppm Calculations"], "jee": ["Converting % to molarity using density", "Mole fraction from molality", "ppm to molarity", "Concentration in mixed solvents"]}, {"id": "mol8", "name": "Volumetric Analysis", "equation": "At equivalence: moles of HвҒә = moles of OHвҒ»  (or NвӮҒVвӮҒ=NвӮӮVвӮӮ)", "explanation": "Indicator changes color at/near equivalence point. Strong acid-strong base: equivalence at pH 7. Weak acid-strong base: pH > 7. Titration curve shape depends on strength of acid/base.", "derived": "Stoichiometry of neutralization. One equivalent of acid reacts with one equivalent of base.", "related": ["Normality", "Buffer Solutions", "pH Calculations", "Indicators", "Back Titration"], "jee": ["Acid-base titration calculations", "Choice of indicator", "Back titration", "Double indicator method"]}, {"id": "mol9", "name": "Stoichiometry of Gaseous Reactions", "equation": "At same T, P: volumes вҲқ moles (Gay-Lussac)", "explanation": "Gay-Lussac's law of combining volumes. At STP, 1 mole = 22.4 L. Volume ratios = mole ratios from equation. Eudiometry: gas analysis problems.", "derived": "From Avogadro's hypothesis that equal volumes of gases at same T, P contain equal molecules.", "related": ["Ideal Gas Law", "Mole Concept", "Limiting Reagent", "Gay-Lussac", "Eudiometry"], "jee": ["Eudiometry (gas analysis)", "Volume of gas produced", "Composition of gas mixture", "Reaction at constant volume/pressure"]}]},
          "Atomic Structure & Chemical Bonding": {"formulas": [{"id": "atm1", "name": "Bohr Model Energy and Radius", "equation": "EвӮҷ = вҲ’13.6ZВІ/nВІ eV;  rвӮҷ = 0.529nВІ/Z Г…", "explanation": "Z = atomic number. Energy more negative = more stable. Ionization energy = 13.6ZВІ/nВІ eV. Wavelength: 1/О» = RZВІ(1/nвӮҒВІвҲ’1/nвӮӮВІ), R = 1.097Г—10вҒ· mвҒ»В№.", "derived": "From centripetal force = Coulomb force and Bohr quantization mvr = nв„Ҹ.", "related": ["Rydberg Formula", "Quantum Numbers", "de Broglie Wavelength", "Energy Level Diagram", "Spectral Series"], "jee": ["Energy of H-like species", "Spectral series lines", "Ionization energy from Bohr", "Radius ratios for H-like"]}, {"id": "atm2", "name": "Quantum Numbers", "equation": "n=1,2,...; l=0 to nвҲ’1; mвӮ—=вҲ’l to +l; mвӮӣ=ВұВҪ", "explanation": "n: shell (energy, size); l: subshell (shape: s=0,p=1,d=2,f=3); mвӮ—: orbital (orientation); mвӮӣ: spin. Capacity: 2nВІ electrons per shell. Hund's rule: maximize unpaired spins.", "derived": "From solutions to SchrГ¶dinger equation for hydrogen. Pauli exclusion: no two electrons have same 4 quantum numbers.", "related": ["Electron Configuration", "Aufbau Principle", "Magnetic Properties", "Hund's Rule", "Pauli Exclusion"], "jee": ["Identifying quantum number sets", "Orbital capacity", "Unpaired electrons", "Magnetic quantum number values"]}, {"id": "atm3", "name": "de Broglie and Heisenberg in Atoms", "equation": "О» = h/mv;  О”xВ·О”p вүҘ h/4ПҖ", "explanation": "Bohr orbit circumference = nО» (justifies quantization). Heisenberg: uncertainty in position Г— momentum вүҘ h/4ПҖ. Electron cannot be in nucleus: if О”x вүҲ 10вҒ»В№вҒө m, О”p and hence KE would be enormous.", "derived": "de Broglie: extending photon momentum p = h/О» to matter. Heisenberg from wave-packet mathematics.", "related": ["Bohr Model", "Quantum Numbers", "Wave-Particle Duality", "Uncertainty Principle", "Standing Waves"], "jee": ["Electron wavelength in Bohr orbit", "Uncertainty in momentum given position", "Why electron isn't in nucleus", "Justifying Bohr quantization"]}, {"id": "atm4", "name": "Bond Order and Molecular Orbital Theory", "equation": "Bond order = (Nb вҲ’ Na)/2", "explanation": "Nb = bonding electrons, Na = antibonding electrons. Higher bond order: shorter, stronger bond. Paramagnetic if unpaired electrons. OвӮӮ: bond order 2, paramagnetic (2 unpaired). NвӮӮ: bond order 3.", "derived": "MO theory: atomic orbitals combine to form bonding (lower energy) and antibonding (higher) MOs.", "related": ["VSEPR", "Hybridization", "Magnetic Properties", "Bond Order", "MO Diagram"], "jee": ["Bond order of OвӮӮ, NвӮӮ, FвӮӮ", "Paramagnetic/diamagnetic from MO", "Stability order of species", "MO filling order"]}, {"id": "atm5", "name": "Hybridization and Geometry", "equation": "spВі: tetrahedral 109.5В°; spВІ: trigonal planar 120В°; sp: linear 180В°", "explanation": "Hybridization = number of Пғ bonds + lone pairs on central atom. spВіd: trigonal bipyramidal; spВіdВІ: octahedral. Lone pairs reduce bond angle. VSEPR: lone pair > bonding pair repulsion.", "derived": "Valence bond theory: mixing of atomic orbitals to form hybrid orbitals of equal energy.", "related": ["VSEPR", "Bond Angle", "Molecular Shape", "Lone Pair Effects", "sp3d Hybridization"], "jee": ["Shape and hybridization of molecules", "Bond angle comparison", "PClвӮ…, SFвӮҶ, XeFвӮ„ structures", "Effect of lone pairs on geometry"]}, {"id": "atm6", "name": "VSEPR and Bond Angles", "equation": "Steric number = Пғ bonds + lone pairs on central atom", "explanation": "Lone pairs at 90В° exert more repulsion than bond pairs. BFвӮғ (120В°) vs NFвӮғ (107В°) vs HвӮӮO (104.5В°). BeClвӮӮ (linear), BClвӮғ (trigonal planar), NHвӮғ (trigonal pyramidal).", "derived": "Sidgwick-Powell/VSEPR: electron pairs arrange to minimize repulsion. Lone pairs occupy more space.", "related": ["Hybridization", "Bond Polarity", "Molecular Geometry", "Steric Number", "Lone Pairs"], "jee": ["Comparing bond angles in series", "Shape of BrFвӮғ, ClFвӮғ", "Bent vs linear molecules", "Explaining decreasing angles in NHвӮғ, HвӮӮO"]}, {"id": "atm7", "name": "Formal Charge", "equation": "FC = Valence eвҒ» вҲ’ Lone pair eвҒ» вҲ’ ВҪ(Bonding eвҒ»)", "explanation": "Preferred structure has formal charges close to 0 and negative FC on more electronegative atom. Used to select best Lewis structure from resonance forms.", "derived": "Hypothetical charge if electrons shared equally. Different from oxidation number.", "related": ["Lewis Structure", "Resonance", "Oxidation Number", "Formal Charge Rules", "Octet Rule"], "jee": ["Lewis structure of SOвӮ„ВІвҒ», NOвӮғвҒ»", "Resonance structure selection", "Formal charge on specific atom", "Comparing structures by FC"]}, {"id": "atm8", "name": "Lattice Energy and Born-Haber Cycle", "equation": "U = вҲ’(NвӮҗ A zвҒәzвҒ» eВІ)/(4ПҖОөвӮҖr)(1вҲ’1/n)  (Madelung)", "explanation": "Lattice energy U: energy to separate 1 mol ionic compound to gaseous ions. Higher for higher charges, smaller ions. Born-Haber cycle applies Hess's law to ionic solids.", "derived": "Born-Haber: О”H_f = IE + EA + sublimation + dissociation + lattice energy.", "related": ["Hess's Law", "Ionic Bonding", "Thermochemistry", "Born-Haber Steps", "Madelung Constant"], "jee": ["Born-Haber cycle calculations", "Comparing lattice energies", "Predicting solubility from lattice energy", "Thermodynamic stability of ionic compounds"]}, {"id": "atm9", "name": "Slater's Rules for Shielding", "equation": "Z_eff = Z вҲ’ Пғ;  Пғ from Slater's rules", "explanation": "Rules: electrons in same group shield 0.35 (0.30 for 1s); nвҲ’1 shell shields 0.85; inner shells shield 1.00. Z_eff determines ionization energy, atomic radius, electronegativity.", "derived": "Empirical rules approximating shielding constant from electron configuration.", "related": ["Ionization Energy", "Atomic Radius", "Electronegativity", "Z_eff", "Penetration Order"], "jee": ["Z_eff for specific electrons", "Comparing IE across period", "Anomalous IEвӮӮ of Be vs B", "Penetration and shielding order"]}]},
          "States of Matter & Thermodynamics": {"formulas": [{"id": "stt1", "name": "Ideal Gas Law and Dalton's Law", "equation": "PV = nRT;  P_total = ОЈPбөў;  Pбөў = ПҮбөў P_total", "explanation": "R = 0.0821 LВ·atm/molВ·K = 8.314 J/molВ·K. Dalton's law: total pressure = sum of partial pressures (non-reacting gases). Mole fraction ПҮбөў = nбөў/n_total.", "derived": "Combined gas laws. Dalton: gases behave independently in mixture.", "related": ["van der Waals", "Kinetic Theory", "Graham's Law", "Partial Pressure", "Mole Fraction"], "jee": ["Gas mixture partial pressures", "Volume fraction = mole fraction at same T,P", "Mean molar mass of mixture", "Collected over water (water vapour correction)"]}, {"id": "stt2", "name": "van der Waals Equation", "equation": "(P + anВІ/VВІ)(V вҲ’ nb) = nRT", "explanation": "a: intermolecular attraction (pressure correction); b: excluded volume (volume correction). Boyle temperature T_B = a/Rb. At T_B, gas behaves ideally over wide pressure range.", "derived": "Corrections to ideal gas: reduced pressure due to attractions, reduced volume available.", "related": ["Ideal Gas Law", "Critical Constants", "Compressibility Factor Z", "Boyle Temperature", "Reduced Variables"], "jee": ["Z = PV/nRT < 1 or > 1", "Boyle temperature", "Critical constants T_c=8a/27Rb", "Compression factor problems"]}, {"id": "stt3", "name": "First Law of Thermodynamics", "equation": "О”U = q + w;  w = вҲ’P_ext О”V (expansion)", "explanation": "q = heat absorbed by system, w = work done ON system. For ideal gas: О”U = nCбөҘО”T. Enthalpy H = U + PV; О”H = qвӮҡ. Relationship: CвӮҡ вҲ’ CбөҘ = R.", "derived": "Conservation of energy applied to thermodynamic systems.", "related": ["Enthalpy", "Hess's Law", "Kirchhoff's Law", "Work Calculation", "Heat Capacity"], "jee": ["Work in isothermal/adiabatic", "О”H vs О”U: О”H=О”U+О”nвӮҳRT", "Reversible vs irreversible work", "CpвҲ’Cv=R problems"]}, {"id": "stt4", "name": "Thermochemistry: Hess's Law", "equation": "О”H_rxn = ОЈО”H_f(products) вҲ’ ОЈО”H_f(reactants)", "explanation": "Hess's law: О”H is path-independent (state function). Standard enthalpy of formation О”H_fВ° of element in standard state = 0. Bond energy method: О”H = ОЈ(bonds broken) вҲ’ ОЈ(bonds formed).", "derived": "Consequence of enthalpy being a state function. Energy must be conserved for any path.", "related": ["First Law", "Kirchhoff's Law", "Bond Energies", "Resonance Energy", "Hess Cycles"], "jee": ["Calculating О”H_rxn from О”H_f", "Bond energy calculations", "Resonance energy", "Lattice energy via Born-Haber"]}, {"id": "stt5", "name": "Gibbs Free Energy and Spontaneity", "equation": "О”G = О”H вҲ’ TО”S;  О”GВ° = вҲ’RT ln K = вҲ’nFEВ°", "explanation": "О”G < 0: spontaneous. О”G = 0: equilibrium. О”G > 0: non-spontaneous. О”GВ° from standard state. Relation to KвӮ‘q and cell EMF. Temperature of spontaneity change when О”H and О”S same sign.", "derived": "Second law: О”S_universe вүҘ 0. Gibbs introduced G = HвҲ’TS as system property for spontaneity at constant T,P.", "related": ["Entropy", "Equilibrium Constant", "Electrochemistry EMF", "Spontaneity", "Temperature Effect"], "jee": ["Predicting spontaneity", "Temperature of sign change", "О”GВ° = вҲ’RT ln K", "Connecting О”GВ° to EВ°cell"]}, {"id": "stt6", "name": "Entropy and Second Law", "equation": "О”S = q_rev/T;  О”S_universe = О”S_sys + О”S_surr вүҘ 0", "explanation": "Entropy: measure of disorder/number of microstates. О”S > 0 for gas formation, dissolution, mixing. Trouton's rule: О”S_vap вүҲ 88 J/molВ·K. Third law: S = 0 at 0 K for perfect crystal.", "derived": "Boltzmann: S = k ln W. Clausius: dS = Оҙq_rev/T.", "related": ["Gibbs Free Energy", "Thermochemistry", "Spontaneity", "Boltzmann Entropy", "Third Law"], "jee": ["Predicting sign of О”S", "О”S for phase changes", "О”S_mix for ideal gases", "Connecting S to spontaneity"]}, {"id": "stt7", "name": "Kirchhoff's Law", "equation": "О”HвӮӮ = О”HвӮҒ + О”CвӮҡ(TвӮӮвҲ’TвӮҒ);  О”CвӮҡ = ОЈCвӮҡ(prod) вҲ’ ОЈCвӮҡ(react)", "explanation": "Variation of enthalpy of reaction with temperature. О”CвӮҡ > 0: О”H increases with T; О”CвӮҡ < 0: О”H decreases. Used when standard enthalpies at one T needed at another T.", "derived": "From definition of CвӮҡ = (вҲӮH/вҲӮT)_P applied to both reactants and products.", "related": ["Hess's Law", "First Law", "Heat Capacity", "Temperature Dependence", "Kirchhoff Equation"], "jee": ["О”H at different temperatures", "Heat capacity difference", "Kirchhoff equation applications", "Temperature dependence of О”H"]}, {"id": "stt8", "name": "Kinetic Theory вҖ” Graham's Law", "equation": "rвӮҒ/rвӮӮ = вҲҡ(MвӮӮ/MвӮҒ);  v_rms = вҲҡ(3RT/M)", "explanation": "Rate of diffusion inversely proportional to вҲҡM. Graham's law used for isotope separation, identification of gases. Also: effusion vs diffusion distinction.", "derived": "From kinetic theory: average KE = (3/2)RT per mole, same for all gases at same T.", "related": ["Ideal Gas Law", "Mean Free Path", "Molecular Speed Distribution", "RMS Speed", "Effusion"], "jee": ["Comparing diffusion rates", "Time to effuse given M ratio", "Mixture composition from effusion", "Separation of isotopes"]}, {"id": "stt9", "name": "Surface Tension and Viscosity", "equation": "P_excess = 2Оі/r (bubble, 1 surface);  4Оі/r (soap bubble, 2 surfaces)", "explanation": "Surface tension Оі: force per unit length (N/m). Capillary rise: h = 2Оі cosОё/(ПҒgr). Viscosity О· decreases with T for liquids, increases for gases. Critical temperature: above it, gas can't be liquefied.", "derived": "Surface tension from excess energy of surface molecules. Capillary rise balances surface tension force vs gravity.", "related": ["States of Matter", "Critical Constants", "Adsorption", "Capillary Rise", "Viscosity Temperature"], "jee": ["Capillary rise problems", "Excess pressure in bubble/drop", "Comparing surface tensions", "Temperature effect on viscosity"]}]},
          "Equilibrium": {"formulas": [{"id": "eql1", "name": "Law of Mass Action вҖ” Kc and Kp", "equation": "Kc = [C]^c[D]^d/[A]^a[B]^b;  Kp = Kc(RT)^О”n", "explanation": "О”n = moles of gaseous products вҲ’ reactants. Kp = Kc when О”n = 0. K dimensionless (activities). Large K: products favoured; small K: reactants favoured. K independent of initial conc.", "derived": "From thermodynamics: О”GВ° = вҲ’RT ln K. Experimentally: ratio at equilibrium.", "related": ["Gibbs Free Energy", "Le Chatelier's Principle", "Reaction Quotient Q", "Temperature Effect on K", "Partial Pressure"], "jee": ["Calculating Kc from equilibrium concentrations", "Kp from Kc given О”n", "Predicting direction from Q vs K", "Equilibrium concentrations from K"]}, {"id": "eql2", "name": "Le Chatelier's Principle", "equation": "Qc < Kc вҹ№ forward;  Qc > Kc вҹ№ reverse", "explanation": "System at equilibrium shifts to oppose change: increase [reactant] вҶ’ forward; increase T вҶ’ endothermic direction; increase P вҶ’ fewer moles of gas; adding inert gas at const V вҶ’ no shift.", "derived": "Consequence of Kc being constant at constant T. Shift restores K.", "related": ["Kc and Kp", "Effect of Temperature", "Reaction Quotient", "Pressure Effect", "Inert Gas Effect"], "jee": ["Predicting shift direction", "Effect of pressure on Haber process", "Temperature effect on K", "Volume change effect"]}, {"id": "eql3", "name": "Degree of Dissociation", "equation": "Оұ: degree of dissociation;  Kc = cОұВІ/(1вҲ’Оұ) вүҲ cОұВІ (Оұ<<1)", "explanation": "For A вҮҢ B + C: if initial moles = 1, at equilibrium: 1вҲ’Оұ, Оұ, Оұ. Kp = Kc(RT)^О”n. Van't Hoff factor i = 1 + (nвҲ’1)Оұ for A вҶ’ n particles.", "derived": "From ICE table (Initial, Change, Equilibrium). Quadratic equation gives Оұ.", "related": ["Kc and Kp", "Colligative Properties", "Acid Dissociation", "van't Hoff Factor", "ICE Table"], "jee": ["Finding Оұ from Kc", "Molar mass from degree of dissociation", "i factor for weak electrolyte", "PClвӮ… dissociation problems"]}, {"id": "eql4", "name": "Acid-Base Equilibria: Ka, Kb, pH", "equation": "pH = вҲ’log[HвҒә];  KaВ·Kb = Kw = 10вҒ»В№вҒҙ  (at 25В°C)", "explanation": "For weak acid HA: Ka = [HвҒә][AвҒ»]/[HA]. [HвҒә] = вҲҡ(KaВ·c) if Оұ<<1. pH of weak acid: pH = ВҪ(pKa вҲ’ log c). Amphoteric salt: pH = ВҪ(pKa1+pKa2).", "derived": "Equilibrium expression for HвӮӮO вҮҢ HвҒә+OHвҒ» (Kw). pH from definition and equilibrium.", "related": ["Kc and Kp", "Hydrolysis", "Buffer Solutions", "pKa", "Henderson-Hasselbalch"], "jee": ["pH of weak acid/base", "Finding Ka from pH", "Relative strength of acids from Ka", "Salt hydrolysis pH calculation"]}, {"id": "eql5", "name": "Buffer Solutions вҖ” Henderson-Hasselbalch", "equation": "pH = pKa + log([AвҒ»]/[HA])", "explanation": "Buffer resists pH change. Maximum buffer capacity at pH = pKa. Buffer range: pKa Вұ 1. Similarly: pOH = pKb + log([B]/[BHвҒә]). Adding strong acid/base to buffer shifts ratio slightly.", "derived": "From Ka expression: [HвҒә] = KaВ·[HA]/[AвҒ»] вҶ’ taking вҲ’log both sides.", "related": ["Ka and Kb", "Titration Curves", "Buffer Capacity", "pH at Equivalence", "Half-Equivalence pH"], "jee": ["pH of buffer solution", "Buffer capacity", "Adding acid/base to buffer", "Designing buffer at given pH"]}, {"id": "eql6", "name": "Solubility Product Ksp", "equation": "Ksp = [M^mвҒә]^m[X^nвҒ»]^n  for M_mX_n", "explanation": "Solubility s: for MX, Ksp = sВІ; for MXвӮӮ, Ksp = 4sВі; for MвӮӮX, Ksp = 4sВі. Common ion effect decreases solubility. Precipitation occurs if ionic product > Ksp.", "derived": "Equilibrium expression for dissolving process. Activities of solids = 1.", "related": ["Common Ion Effect", "Precipitation", "Complex Ion Equilibria", "Solubility Rules", "Ion Product"], "jee": ["Calculating solubility from Ksp", "Common ion suppression", "Precipitation conditions", "Ksp comparison to predict precipitate"]}, {"id": "eql7", "name": "Common Ion Effect and Simultaneous Equilibria", "equation": "[AвҒ»] from added salt suppresses Оұ of HA", "explanation": "Adding NaA to HA solution reduces [HвҒә] (Le Chatelier). Similarly, adding CaВІвҒә reduces solubility of CaFвӮӮ via Ksp. Selective precipitation: precipitate one ion while other remains in solution.", "derived": "From Le Chatelier's principle: common ion shifts equilibrium back.", "related": ["Ksp", "Buffer Solutions", "Degree of Dissociation", "Selective Precipitation", "pH Effect on Solubility"], "jee": ["Solubility in presence of common ion", "Selective precipitation", "pH of buffer using common ion", "Suppression of weak acid dissociation"]}, {"id": "eql8", "name": "Salt Hydrolysis", "equation": "For salt of weak acid+strong base: pH = 7 + ВҪ(pKa + log c)", "explanation": "Anion of weak acid hydrolyzes: AвҒ»+HвӮӮO вҮҢ HA+OHвҒ», Kh = Kw/Ka. Cation of weak base: BHвҒә+HвӮӮO вҮҢ B+HвӮғOвҒә, Kh = Kw/Kb. Degree of hydrolysis h = вҲҡ(Kh/c).", "derived": "From equilibrium of hydrolysis reaction combined with Kw = KaВ·Kb.", "related": ["Ka and Kb", "Kw", "Buffer Solutions", "Hydrolysis Constant", "Amphiprotic Salts"], "jee": ["pH of CHвӮғCOONa solution", "pH of NHвӮ„Cl solution", "Degree of hydrolysis", "Salt of weak acid and weak base"]}, {"id": "eql9", "name": "Reaction Quotient Q and Equilibrium", "equation": "Q = Kc: equilibrium;  Q < Kc: forward;  Q > Kc: reverse", "explanation": "Q has same form as Kc but uses any concentrations, not equilibrium. Comparing Q to K gives reaction direction. When equilibrium reached, Q = K. Valid for all types of equilibria.", "derived": "From definition of Kc. Non-equilibrium concentrations give Q вү  K, driving reaction.", "related": ["Kc and Kp", "Le Chatelier's Principle", "Gibbs Free Energy", "Direction of Reaction", "Q vs K"], "jee": ["Direction of reaction from Q", "Predicting shifts", "О”G = RT ln(Q/K)", "Approaching equilibrium from either side"]}]},
          "Electrochemistry & Chemical Kinetics": {"formulas": [{"id": "elk1", "name": "Standard EMF and Electrode Potential", "equation": "EВ°cell = EВ°cathode вҲ’ EВ°anode;  О”GВ° = вҲ’nFEВ°", "explanation": "SHE (standard hydrogen electrode): EВ° = 0. Higher EВ°: better oxidizing agent. Spontaneous: EВ°cell > 0 (О”GВ° < 0). F = 96485 C/mol вүҲ 96500 C/mol.", "derived": "EMF = potential difference between electrodes. О”G = вҲ’nFE (from electrical work = Gibbs energy).", "related": ["Nernst Equation", "Gibbs Free Energy", "Electrolysis", "SHE Reference", "Cell Notation"], "jee": ["Cell EMF from standard potentials", "Spontaneity of redox reaction", "О”G from EВ°cell", "Relating EВ° to K: EВ°=RT/nFВ·ln K"]}, {"id": "elk2", "name": "Nernst Equation", "equation": "E = EВ° вҲ’ (RT/nF) ln Q = EВ° вҲ’ (0.0592/n) log Q  (at 25В°C)", "explanation": "At equilibrium E = 0: EВ° = (0.0592/n) log K. Concentration cell: EВ° = 0, E = (0.0592/n) log([CвӮӮ]/[CвӮҒ]). pH electrode: E changes 0.0592 V per pH unit.", "derived": "From О”G = О”GВ° + RT ln Q and О”G = вҲ’nFE.", "related": ["Standard EMF", "Gibbs Free Energy", "pH Measurement", "Concentration Cell", "Nernst at Equilibrium"], "jee": ["EMF of concentration cell", "Finding K from EВ°", "Electrode potential at non-standard conc", "pH from cell potential"]}, {"id": "elk3", "name": "Faraday's Laws of Electrolysis", "equation": "m = ZIt = MIt/nF  (Z = M/nF, electrochemical equivalent)", "explanation": "First law: mass deposited вҲқ charge (Q = It). Second law: masses of different substances deposited by same charge вҲқ equivalent weights. 1 Faraday deposits 1 equivalent.", "derived": "One mole of electrons = 1 Faraday = 96500 C. n electrons needed to deposit 1 mole of M^n+ ions.", "related": ["Standard EMF", "Electrolytic Cells", "Electrode Reactions", "Electrochemical Equivalent", "Faraday Constant"], "jee": ["Mass deposited in electrolysis", "Time for deposition", "Simultaneous electrolysis", "Faraday efficiency"]}, {"id": "elk4", "name": "Rate Law and Rate Constant", "equation": "r = k[A]^m[B]^n;  units of k: (mol/L)^(1вҲ’n)/s", "explanation": "Rate order determined experimentally, not from equation. Zero order: r=k, [A]=[A]вӮҖвҲ’kt. First order: r=k[A], [A]=[A]вӮҖe^(вҲ’kt). Second order: 1/[A]=1/[A]вӮҖ+kt.", "derived": "Empirical. From mechanism: rate = k[intermediates] from rate-determining step.", "related": ["Arrhenius Equation", "Half-Life", "Integrated Rate Law", "Rate Constant Units", "Pseudo First Order"], "jee": ["Determining order from data", "Units of k", "Pseudo first order", "Method of initial rates"]}, {"id": "elk5", "name": "Integrated Rate Laws and Half-Life", "equation": "First order: tВҪ = 0.693/k  (independent of [A]вӮҖ)", "explanation": "Zero order tВҪ = [A]вӮҖ/2k. Second order tВҪ = 1/k[A]вӮҖ. First order: ln([A]/[A]вӮҖ) = вҲ’kt. Radioactive decay is always first order. Parallel/consecutive reactions.", "derived": "Integration of rate law differential equation for each order.", "related": ["Rate Law", "Arrhenius Equation", "Nuclear Decay", "Half-Life Formula", "Concentration vs Time"], "jee": ["Finding k from half-life", "Concentration after n half-lives", "Mixed order reactions", "Time for 75% completion"]}, {"id": "elk6", "name": "Arrhenius Equation", "equation": "k = Ae^(вҲ’Ea/RT);  ln(kвӮӮ/kвӮҒ) = (Ea/R)(1/TвӮҒвҲ’1/TвӮӮ)", "explanation": "A = pre-exponential (frequency) factor. Ea = activation energy. Rule of thumb: k doubles per 10В°C rise near room T. Catalyst lowers Ea without changing О”H.", "derived": "From collision theory: fraction of molecules with energy вүҘ Ea is e^(вҲ’Ea/RT).", "related": ["Rate Constant", "Catalysis", "Transition State Theory", "Frequency Factor", "Temperature Coefficient"], "jee": ["Finding Ea from k at two temperatures", "Effect of T on rate", "Catalyst effect on Ea", "Graph of ln k vs 1/T (slope = вҲ’Ea/R)"]}, {"id": "elk7", "name": "Conductance and Kohlrausch's Law", "equation": "Оӣm = ОӣmВ° вҲ’ KвҲҡc  (strong electrolytes)", "explanation": "Conductance G = 1/R. Specific conductance Оә = GВ·l/A. Molar conductance Оӣm = Оә/c. Kohlrausch: ОӣmВ° = ОЈО»_ionsВ°. Used to find ОӣmВ° of weak electrolytes. Degree of dissociation Оұ = Оӣm/ОӣmВ°.", "derived": "Kohlrausch from independent migration of ions at infinite dilution.", "related": ["Faraday's Laws", "Degree of Dissociation", "Electrolytic Cells", "Molar Conductivity", "Kohlrausch Constant"], "jee": ["Оӣm of weak acid from strong electrolyte data", "Degree of dissociation from conductance", "Ka from conductance", "Debye-HГјckel-Onsager slope K"]}, {"id": "elk8", "name": "Batteries and Corrosion", "equation": "Fuel cell: HвӮӮ + ВҪOвӮӮ вҶ’ HвӮӮO;  EВ°cell = 1.23 V", "explanation": "Primary (non-rechargeable): LeclanchГ©, lithium. Secondary (rechargeable): lead-acid, Ni-Cd, Li-ion. Rusting: Fe вҶ’ FeВІвҒә + 2eвҒ» (anode); OвӮӮ + HвӮӮO + 4eвҒ» вҶ’ 4OHвҒ» (cathode). Galvanized Fe: Zn acts as sacrificial anode.", "derived": "Electrochemical cells convert chemical energy to electrical (galvanic) or vice versa (electrolytic).", "related": ["Standard EMF", "Nernst Equation", "Electrolysis", "Corrosion Prevention", "Sacrificial Anode"], "jee": ["Lead-acid battery reactions", "Fuel cell electrode reactions", "Corrosion prevention methods", "Sacrificial anode problems"]}, {"id": "elk9", "name": "Mechanism and Rate-Determining Step", "equation": "Slowest step determines rate; r = k[intermediates]", "explanation": "Steady-state approximation: d[intermediate]/dt вүҲ 0. Pre-equilibrium: fast equilibrium before slow step. Molecularity of elementary step = order. Overall order вү  molecularity for multi-step.", "derived": "From sequential elementary steps. Bottleneck principle: slowest step limits overall rate.", "related": ["Rate Law", "Activation Energy", "Catalysis", "Steady State", "Pre-equilibrium"], "jee": ["Deriving rate from mechanism", "Identifying RDS from rate law", "Steady-state approximation", "Pre-equilibrium derivation"]}]},
          "Solid State & Surface Chemistry": {"formulas": [{"id": "sol1", "name": "Unit Cell and Packing Efficiency", "equation": "BCC: 2 atoms, PE=68%; FCC/CCP: 4 atoms, PE=74%; Simple cubic: 1 atom, PE=52%", "explanation": "Edge length a related to radius r: SC: a=2r; BCC: 4r=вҲҡ3a; FCC: 4r=вҲҡ2a. Packing efficiency = (volume of atoms / volume of unit cell) Г— 100%.", "derived": "By counting atoms per unit cell (corner Г— 1/8, face Г— 1/2, body Г— 1, edge Г— 1/4) and calculating geometry.", "related": ["Density of Crystal", "Void Analysis", "Close Packing", "Coordination Number", "Unit Cell Types"], "jee": ["Density from unit cell: ПҒ=ZM/NвӮҗaВі", "Edge length from radius", "Packing efficiency calculation", "Number of atoms per unit cell"]}, {"id": "sol2", "name": "Density of Crystal", "equation": "ПҒ = ZM/(NвӮҗ aВі)", "explanation": "Z = atoms per unit cell, M = molar mass (g/mol), a = edge length (cm), NвӮҗ = 6.022Г—10ВІВі. Used to determine Z or M or a when two are known. Units: g/cmВі.", "derived": "Mass of unit cell = ZM/NвӮҗ; Volume = aВі; density = mass/volume.", "related": ["Unit Cell", "Packing Efficiency", "X-ray Diffraction", "Bragg's Equation", "Crystal Density Formula"], "jee": ["Calculating crystal density", "Finding edge length from density", "Identifying unit cell type", "Molar mass from density and edge length"]}, {"id": "sol3", "name": "Voids and Radius Ratio", "equation": "Tetrahedral void: r/R = 0.225; Octahedral void: r/R = 0.414", "explanation": "In FCC/CCP: N atoms вҶ’ N octahedral voids + 2N tetrahedral voids. ZnS (zinc blende): ZnВІвҒә in alternate tetrahedral voids. NaCl: NaвҒә in all octahedral voids. Radius ratio predicts crystal structure.", "derived": "Geometry of void fitting: largest sphere fitting into tetrahedral/octahedral hole in close-packing.", "related": ["Unit Cell", "Crystal Structures", "Ionic Radii", "Radius Ratio Rules", "Tetrahedral Holes"], "jee": ["Number of voids in FCC", "Radius ratio for coordination number", "Identifying structure from radii", "ZnS vs NaCl vs CsCl structures"]}, {"id": "sol4", "name": "Crystal Defects", "equation": "Schottky: equal cation+anion vacancies; Frenkel: ion displaced to interstitial", "explanation": "Schottky: density decreases (vacancies), common in NaCl. Frenkel: density unchanged (ions move to void), common in AgCl, ZnS. F-centre: trapped electron, causes color. Doping creates n or p-type semiconductors.", "derived": "Thermal energy creates vacancies. Smaller ions (AgвҒә) more likely to shift to interstitial.", "related": ["Unit Cell", "Semiconductors", "Point Defects", "Schottky vs Frenkel", "Non-stoichiometry"], "jee": ["Identifying defect type", "Effect on density", "Metal excess/deficiency defects", "Non-stoichiometric compounds"]}, {"id": "sol5", "name": "Bragg's Equation for X-ray Diffraction", "equation": "nО» = 2d sinОё", "explanation": "n = order of reflection, О» = X-ray wavelength, d = interplanar spacing, Оё = angle of incidence. Used to determine crystal structure and interplanar distances.", "derived": "Constructive interference when path difference 2d sinОё = nО».", "related": ["Unit Cell", "Crystal Structure", "Electron Diffraction", "Interplanar Spacing", "Diffraction Order"], "jee": ["Calculating d-spacing from Оё", "Identifying crystal planes", "X-ray wavelength from Bragg", "Structure determination"]}, {"id": "sol6", "name": "Adsorption: Freundlich Isotherm", "equation": "x/m = kP^(1/n)  (1/n < 1);  log(x/m) = log k + (1/n)log P", "explanation": "x/m = amount adsorbed per gram adsorbent. Physisorption: multilayer, low T, reversible, low Ea, О”H вүҲ вҲ’20 kJ/mol. Chemisorption: monolayer, high T, irreversible, high Ea, О”H вүҲ вҲ’200 kJ/mol.", "derived": "Empirical isotherm. Linear form: log(x/m) vs log P gives slope 1/n and intercept log k.", "related": ["Langmuir Isotherm", "Colloids", "Catalysis", "Adsorption Types", "BET Surface Area"], "jee": ["Adsorption isotherm slope/intercept", "Freundlich vs Langmuir", "Physisorption vs chemisorption", "Effect of T on adsorption"]}, {"id": "sol7", "name": "Colloids: Properties and Types", "equation": "Tyndall effect: colloidal particles (1вҖ“1000 nm) scatter light", "explanation": "Lyophilic (solvent-loving): stable, reversible (gum, starch). Lyophobic (solvent-fearing): unstable, irreversible (metal sols). Coagulation by electrolyte: Hardy-Schulze rule (higher charge вҶ’ more effective). Dialysis removes ions.", "derived": "Properties follow from particle size between solution (< 1nm) and suspension (> 1Ојm).", "related": ["Adsorption: Freundlich Isotherm", "Brownian Motion", "Electrophoresis", "Coagulation", "Tyndall Effect"], "jee": ["Tyndall effect explanation", "Hardy-Schulze rule", "Coagulation and peptization", "Emulsions and surfactants"]}, {"id": "sol8", "name": "Langmuir Adsorption Isotherm", "equation": "Оё = KP/(1+KP);  P/(x/m) = P/(x/m)_mono + 1/K(x/m)_mono", "explanation": "Оё = fraction of surface covered. Monolayer adsorption. At low P: Оё вүҲ KP (linear); at high P: Оё вҶ’ 1 (saturation). Plot P/(x/m) vs P: slope = 1/(x/m)_mono.", "derived": "Dynamic equilibrium between adsorption and desorption rates. Rate_ads = kвӮҒ(1вҲ’Оё)P; Rate_des = kвӮӮОё.", "related": ["Freundlich Isotherm", "Catalysis", "Surface Area", "CMC", "Monolayer Coverage"], "jee": ["Langmuir linear form", "Coverage fraction calculation", "Comparing with Freundlich", "Catalyst surface area from Langmuir"]}, {"id": "sol9", "name": "Electrical Properties of Solids", "equation": "Conductors: Пғ ~ 10вҒ¶вҖ“10вҒё S/m; Semiconductors: ~10вҒ»вҒҙвҖ“10вҒҙ; Insulators: <10вҒ»В№вҒ°", "explanation": "Band gap: conductors (0 eV), Si (1.1 eV), Ge (0.67 eV), diamond (6 eV). Ferromagnetism: domains aligned. Antiferromagnetism: antiparallel alignment вҶ’ 0 net moment. Ferrimagnetism: unequal antiparallel.", "derived": "Band theory of solids. Overlap of atomic orbitals forms bands; gap between valence and conduction band.", "related": ["Semiconductors", "Crystal Defects", "Magnetic Properties", "Band Gap", "Ferromagnetism"], "jee": ["Classifying by band gap", "Magnetic property from electron count", "Superconductivity basics", "n-type and p-type semiconductors"]}]},
          "Solutions": {"formulas": [{"id": "sln1", "name": "Raoult's Law", "equation": "PвӮҗ = ПҮвӮҗ PвӮҗВ°;  P_total = ПҮвӮҗPвӮҗВ° + ПҮ_bPбөҰВ°", "explanation": "For ideal solutions: partial vapour pressure вҲқ mole fraction. Positive deviation: AвҖ“B interactions weaker than AвҖ“A, BвҖ“B (e.g. acetone+CSвӮӮ). Negative deviation: AвҖ“B stronger (e.g. acetone+CHClвӮғ).", "derived": "Empirical law for ideal mixtures where intermolecular forces AвҖ“B = AвҖ“A = BвҖ“B.", "related": ["Vapour Pressure", "Colligative Properties", "Henry's Law", "Ideal Solution", "Azeotrope"], "jee": ["Vapour pressure of mixture", "Identifying deviation type", "Azeotropic mixtures", "Composition of vapour from Raoult"]}, {"id": "sln2", "name": "Relative Lowering of Vapour Pressure", "equation": "(PВ° вҲ’ P)/PВ° = ПҮ_solute = nвӮӮ/(nвӮҒ+nвӮӮ)", "explanation": "Colligative property: depends only on number of solute particles, not nature. For dilute solutions: (PВ°вҲ’P)/PВ° вүҲ nвӮӮ/nвӮҒ = wвӮӮMвӮҒ/(wвӮҒMвӮӮ). Used to find molar mass of solute.", "derived": "From Raoult's law: P = ПҮ_solvent Г— PВ° вҶ’ (PВ°вҲ’P)/PВ° = 1 вҲ’ ПҮ_solvent = ПҮ_solute.", "related": ["Raoult's Law", "Molar Mass Determination", "van't Hoff Factor", "Colligative Properties", "Dilute Solution"], "jee": ["Finding molar mass from VP lowering", "Vapour pressure of solution", "Comparing VP of different solutions", "Association and dissociation effects"]}, {"id": "sln3", "name": "Elevation of Boiling Point", "equation": "О”Tb = KbВ·m;  Kb = RT_bВІMвӮҒ/1000О”H_vap", "explanation": "Kb (ebullioscopic constant) depends only on solvent. For water: Kb = 0.512 KВ·kg/mol. Normal boiling point elevated by solute. Used to find molar mass. van't Hoff factor i multiplies m for electrolytes.", "derived": "From Clausius-Clapeyron and Raoult's law. Boiling point where vapour pressure = external pressure.", "related": ["Raoult's Law", "Molar Mass", "van't Hoff Factor", "Ebullioscopic Constant", "Electrolyte Elevation"], "jee": ["О”Tb calculation", "Kb of solvent", "Molar mass from О”Tb", "Electrolyte vs non-electrolyte comparison"]}, {"id": "sln4", "name": "Depression of Freezing Point", "equation": "О”Tf = KfВ·m;  Kf(water) = 1.86 KВ·kg/mol", "explanation": "Freezing point depressed by solute. Used widely (antifreeze). Kf (cryoscopic constant) larger than Kb for most solvents. О”Tf = iВ·KfВ·m for electrolytes. Kf = RT_fВІMвӮҒ/1000О”H_fus.", "derived": "Solute lowers chemical potential of solvent вҶ’ equilibrium with solid at lower T.", "related": ["Boiling Point Elevation", "van't Hoff Factor", "Molar Mass", "Cryoscopic Constant", "Antifreeze"], "jee": ["Antifreeze calculation", "Molar mass from О”Tf", "Comparing Kf and Kb", "О”Tf for electrolytes using i"]}, {"id": "sln5", "name": "Osmotic Pressure", "equation": "ПҖ = iMRT = icRT/M", "explanation": "Van't Hoff equation (dilute solution). ПҖ = osmotic pressure. Isotonic solutions: same ПҖ. Reverse osmosis: apply pressure > ПҖ. Osmotic pressure used for high molar mass polymers (most sensitive method).", "derived": "Thermodynamic argument: osmosis continues until chemical potentials equalized. Van't Hoff analogy to ideal gas PV=nRT.", "related": ["Raoult's Law", "van't Hoff Factor", "Colligative Properties", "Isotonic Solutions", "Reverse Osmosis"], "jee": ["Osmotic pressure calculation", "Isotonic solution concentration", "Molar mass of polymer from ПҖ", "Comparing sensitivity of methods"]}, {"id": "sln6", "name": "van't Hoff Factor i", "equation": "i = observed colligative property / expected (non-electrolyte)", "explanation": "For electrolytes: i > 1 (dissociation). For association (like acetic acid in benzene): i < 1. i = 1 + (nвҲ’1)Оұ for dissociation into n ions. Relates to degree of dissociation/association.", "derived": "Ratio accounting for actual number of particles vs formula units.", "related": ["Colligative Properties", "Degree of Dissociation", "Electrolytes", "Association", "Dissociation Constant"], "jee": ["Finding Оұ from i", "i for strong/weak electrolytes", "Effect of i on О”Tf, О”Tb, ПҖ", "Acetic acid dimerization in benzene"]}, {"id": "sln7", "name": "Henry's Law", "equation": "P_gas = K_H В· ПҮ_gas (dissolved)", "explanation": "At constant T: amount of gas dissolved вҲқ partial pressure. K_H increases with T (gas less soluble at higher T). Used for carbonated drinks, OвӮӮ in blood. K_H differs from Raoult's PвӮҗВ° for non-ideal solutions.", "derived": "Empirical law for dilute solutions of volatile solute. Raoult's law applies to solvent; Henry's to solute.", "related": ["Henry's Law", "Solubility of Gases", "Atmospheric Chemistry", "Carbonation", "Mole Fraction"], "jee": ["Solubility of gas at given P", "Comparing K_H values", "Temperature effect on gas solubility", "Carbonated drink problems"]}, {"id": "sln8", "name": "Ideal vs Non-Ideal Solutions", "equation": "Ideal: О”H_mix=0, О”V_mix=0, obeys Raoult's law throughout", "explanation": "Non-ideal: +ve deviation (О”H_mix > 0, max boiling azeotrope) or вҲ’ve deviation (О”H_mix < 0, min boiling azeotrope). Azeotrope: boils at constant composition. Cannot be separated by fractional distillation.", "derived": "Raoult's law is exact for ideal solutions. Non-ideal: activity coefficient Оі вү  1.", "related": ["Raoult's Law", "Vapour Pressure", "Activity Coefficient", "Azeotrope Types", "Distillation"], "jee": ["Identifying deviation from О”H_mix sign", "Azeotrope type from deviation", "Ethanol-water azeotrope", "HCl-water negative deviation"]}, {"id": "sln9", "name": "Solubility and Temperature Dependence", "equation": "For solid in liquid: ln(sвӮӮ/sвӮҒ) = (О”H_sol/R)(1/TвӮҒвҲ’1/TвӮӮ)", "explanation": "If О”H_sol > 0 (endothermic): solubility increases with T. If < 0: decreases with T. CeвӮӮ(SOвӮ„)вӮғ is exception (decreases). Gas solubility always decreases with T (Henry's law).", "derived": "From van't Hoff equation applied to dissolution equilibrium.", "related": ["Henry's Law", "Ksp", "Gibbs Free Energy", "Solubility Product", "Temperature Coefficient"], "jee": ["Predicting solubility trend with T", "Exception cases (CeвӮӮSOвӮ„)вӮғ", "Gas vs solid solubility trends", "Solubility product temperature dependence"]}]},
        }
